using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketModelService modelService) : ControllerBase
{
    /// <summary>Trains the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResult> Train()
    {
        var result = modelService.TrainAndEvaluate();
        return Ok(result);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<object> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest(new { error = "Subject or Description is required." });

        if (request.Priority is < 1 or > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        if (!modelService.IsTrained)
            return BadRequest(new { error = "Model has not been trained. POST to /api/tickets/train first." });

        var prediction = modelService.Predict(request);

        return Ok(new
        {
            predictedCategory = prediction.Category,
            scores = prediction.Score
        });
    }
}

